#include <semaphore.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/wait.h>
#include <unistd.h>

int main(void) {
    int *counter = (int *)mmap(NULL, sizeof(int),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_ANONYMOUS, -1, 0);
    *counter = 0;

    sem_t *sem = sem_open("/kf_sem_mutex", O_CREAT | O_EXCL, 0644, 1);

    for (int i = 0; i < 2; i++) {
        if (fork() == 0) {
            for (int j = 0; j < 1000; j++) {
                sem_wait(sem);
                (*counter)++;
                sem_post(sem);
            }
            _exit(0);
        }
    }
    for (int i = 0; i < 2; i++) wait(NULL);

    printf("Counter: %d\n", *counter);

    sem_close(sem);
    sem_unlink("/kf_sem_mutex");
    munmap(counter, sizeof(int));
    return 0;
}

